#include <vector>
using namespace std;

const long long MOD = 1000000007;

long long solve(vector<long long> nums, vector<vector<long long>> queries) {
    for (auto& query : queries) {
        long long li = query[0], ri = query[1], ki = query[2], vi = query[3];
        long long idx = li;
        while (idx <= ri) {
            nums[idx] = (nums[idx] * vi) % MOD;
            idx += ki;
        }
    }
    long long xor_result = 0;
    for (long long num : nums) {
        xor_result ^= num;
    }
    return xor_result;
}

